  1	import { Chart, ChartAxis, ChartBar, ChartStack, ChartThemeColor, createContainer } from '@patternfly/react-charts/victory';
  2	import {
  3	  Bullseye,
  4	  Button,
  5	  EmptyState,
  6	  EmptyStateBody,
  7	  EmptyStateHeader,
  8	  EmptyStateVariant,
  9	  Flex,
 10	  FlexItem,
 11	  PopoverPosition,
 12	  Spinner,
 13	  Text,
 14	  TextVariants,
 15	  Tooltip
 16	} from '@patternfly/react-core';
 17	import {
 18	  AngleDoubleLeftIcon,
 19	  AngleDoubleRightIcon,
 20	  AngleLeftIcon,
 21	  AngleRightIcon,
 22	  QuestionCircleIcon,
 23	  SearchMinusIcon,
 24	  SearchPlusIcon
 25	} from '@patternfly/react-icons';
 26	import * as React from 'react';
 27	import { useTranslation } from 'react-i18next';
 28	import { NamedMetric, TopologyMetrics } from '../../api/loki';
 29	import { TimeRange } from '../../utils/datetime';
 30	import { getDateMsInSeconds } from '../../utils/duration';
 31	import { localStorageHistogramGuidedTourDoneKey, useLocalStorage } from '../../utils/local-storage-hook';
 32	import { getFormattedValue } from '../../utils/metrics';
 33	import {
 34	  ChartDataPoint,
 35	  Dimensions,
 36	  getDomainDisplayText,
 37	  getDomainFromRange,
 38	  getHistogramRangeFromLimit,
 39	  observeDimensions,
 40	  toHistogramDatapoints,
 41	  toNamedMetric
 42	} from '../../utils/metrics-helper';
 43	import { TruncateLength } from '../dropdowns/truncate-dropdown';
 44	import { GuidedTourHandle } from '../guided-tour/guided-tour';
 45	import BrushHandleComponent from './brush-handle';
 46	import './histogram.css';
 47	import './metrics-content.css';
 48	
 49	export const VoronoiContainer = createContainer('voronoi', 'brush');
 50	
 51	export interface HistogramProps {
 52	  id: string;
 53	  loading: boolean;
 54	  totalMetric: NamedMetric;
 55	  limit: number;
 56	  isDark: boolean;
 57	  range?: TimeRange;
 58	  guidedTourHandle: GuidedTourHandle | null;
 59	  setRange: (tr: TimeRange) => void;
 60	  moveRange: (next: boolean) => void;
 61	  zoomRange: (zoom: boolean) => void;
 62	}
 63	
 64	export const Histogram: React.FC<HistogramProps> = ({
 65	  id,
 66	  loading,
 67	  totalMetric,
 68	  limit,
 69	  isDark,
 70	  range,
 71	  guidedTourHandle,
 72	  setRange,
 73	  moveRange,
 74	  zoomRange
 75	}) => {
 76	  const { t } = useTranslation('plugin__netobserv-plugin');
 77	
 78	  const datapoints: ChartDataPoint[] = toHistogramDatapoints(totalMetric);
 79	  const defaultRange = getHistogramRangeFromLimit(totalMetric, limit);
 80	  const [displayedRange, setDisplayedRange] = React.useState<TimeRange>();
 81	
 82	  React.useEffect(() => {
 83	    if (range) {
 84	      setDisplayedRange(range);
 85	    }
 86	  }, [range]);
 87	
 88	  const [tooltipsTrigger, setTooltipsTrigger] = React.useState<'manual' | 'mouseenter'>('mouseenter');
 89	  const containerRef = React.useRef<HTMLDivElement>(null);
 90	  const zoomRef = React.createRef<HTMLInputElement>();
 91	  const pageRef = React.createRef<HTMLInputElement>();
 92	  const arrowRef = React.createRef<HTMLInputElement>();
 93	
 94	  // eslint-disable-next-line @typescript-eslint/no-explicit-any
 95	  const animate: any = {
 96	    duration: 1500,
 97	    animationWhitelist: ['data', 'domain']
 98	  };
 99	
100	  const [dimensions, setDimensions] = React.useState<Dimensions>({ width: 3000, height: 250 });
101	  React.useEffect(() => {
102	    return observeDimensions(containerRef, dimensions, setDimensions);
103	  }, [containerRef, dimensions, setDimensions]);
104	
105	  const moveHistogramRange = React.useCallback(
106	    (next: boolean) => {
107	      containerRef.current?.focus();
108	
109	      const r = range ? range : defaultRange;
110	      const rSize = r.to - r.from;
111	
112	      let start = r.from - rSize;
113	      if (next) {
114	        start = r.to;
115	      }
116	      const end = start + rSize;
117	
118	      //try to get new range using limit
119	      let updatedRange = getHistogramRangeFromLimit(totalMetric, limit, start);
120	
121	      //else fallback on previous / next range keeping actual width
122	      if (!updatedRange.from || !updatedRange.to) {
123	        const minTime = getDateMsInSeconds(Math.min(...datapoints.map(dp => dp.x.getTime())));
124	        const maxTime = getDateMsInSeconds(Math.max(...datapoints.map(dp => dp.x.getTime())));
125	
126	        updatedRange = {
127	          from: start > minTime ? start : minTime,
128	          to: end < maxTime ? end : maxTime
129	        };
130	      }
131	
132	      if (updatedRange.from && updatedRange.to && updatedRange.from < updatedRange.to) {
133	        setRange(updatedRange);
134	      } else {
135	        setRange(defaultRange);
136	      }
137	    },
138	    [containerRef, datapoints, defaultRange, limit, range, setRange, totalMetric]
139	  );
140	
141	  const onKeyDown = React.useCallback(
142	    (key: string) => {
143	      switch (key) {
144	        case 'ArrowRight':
145	          moveRange(true);
146	          break;
147	        case 'ArrowLeft':
148	          moveRange(false);
149	          break;
150	        case '+':
151	          zoomRange(true);
152	          break;
153	        case '-':
154	          zoomRange(false);
155	          break;
156	        case 'PageUp':
157	          moveHistogramRange(true);
158	          break;
159	        case 'PageDown':
160	          moveHistogramRange(false);
161	          break;
162	      }
163	    },
164	    [moveHistogramRange, moveRange, zoomRange]
165	  );
166	
167	  const zoomButtonTips = React.useCallback(() => {
168	    return t(
169	      // eslint-disable-next-line max-len
170	      'Zoom in / zoom out the histogram displayed time range. The selected time range in the top right corner will adapt accordingly. You can also use the plus or minus buttons while the histogram is focused.'
171	    );
172	  }, [t]);
173	
174	  const pageButtonTips = React.useCallback(() => {
175	    return t(
176	      // eslint-disable-next-line max-len
177	      'Move the selected range to filter the table below as time based pagination. You can also use the page up or down buttons while the histogram is focused.'
178	    );
179	  }, [t]);
180	
181	  const arrowButtonTips = React.useCallback(() => {
182	    return t(
183	      // eslint-disable-next-line max-len
184	      'Shift the histogram displayed time range. The selected time range in the top right corner will adapt accordingly. You can also use the arrow left or right buttons while the histogram is focused.'
185	    );
186	  }, [t]);
187	
188	  const [guidedTourDone, setGuidedTourDone] = useLocalStorage<boolean>(localStorageHistogramGuidedTourDoneKey);
189	  React.useEffect(() => {
190	    if (!guidedTourHandle) {
191	      return;
192	    }
193	
194	    guidedTourHandle.clearOnIndexChangeListener();
195	    guidedTourHandle.updateTourItems([
196	      {
197	        title: t('Histogram'),
198	        description: t(
199	          // eslint-disable-next-line max-len
200	          'The following bar chart represents the number of logs over time. You can select a portion of it to drill down into the selected time range, accordingly/consequently filtering the following flows information.'
201	        ),
202	        assetName: 'histogram.gif',
203	        minWidth: '600px',
204	        ref: containerRef
205	      },
206	      {
207	        title: t('Zoom buttons'),
208	        description: zoomButtonTips(),
209	        assetName: 'histogram-zoom.gif',
210	        position: PopoverPosition.bottom,
211	        ref: zoomRef
212	      },
213	      {
214	        title: t('Arrow buttons'),
215	        description: arrowButtonTips(),
216	        ref: arrowRef
217	      },
218	      {
219	        title: t('Page buttons'),
220	        description: pageButtonTips(),
221	        assetName: 'histogram-pages.gif',
222	        minWidth: '600px',
223	        position: PopoverPosition.bottom,
224	        ref: pageRef
225	      }
226	    ]);
227	
228	    if (!guidedTourDone) {
229	      setGuidedTourDone(true);
230	      guidedTourHandle.startTour();
231	    }
232	
233	    guidedTourHandle.addOnIndexChangeListener(index =>
234	      setTooltipsTrigger(index !== undefined ? 'manual' : 'mouseenter')
235	    );
236	  }, [
237	    arrowButtonTips,
238	    arrowRef,
239	    containerRef,
240	    guidedTourDone,
241	    guidedTourHandle,
242	    pageButtonTips,
243	    pageRef,
244	    setGuidedTourDone,
245	    t,
246	    zoomButtonTips,
247	    zoomRef
248	  ]);
249	
250	  return (
251	    <div
252	      id={`chart-${id}`}
253	      className={`metrics-content-div ${loading ? 'loading' : ''}`}
254	      ref={containerRef}
255	      tabIndex={0}
256	      onKeyDown={e => onKeyDown(e.key)}
257	    >
258	      <Flex className="histogram-range-container" direction={{ default: 'row' }}>
259	        <FlexItem flex={{ default: 'flex_1' }}>
260	          <Text component={TextVariants.p}>{t('Number of logs over time')}</Text>
261	        </FlexItem>
262	        <FlexItem>
263	          <Tooltip
264	            content={arrowButtonTips()}
265	            trigger={tooltipsTrigger}
266	            isVisible={tooltipsTrigger === 'manual' ? false : undefined}
267	          >
268	            <Button
269	              icon={<AngleDoubleLeftIcon />}
270	              variant="plain"
271	              className={`metrics-content-button ${loading ? 'loading' : ''}`}
272	              onClick={() => moveRange(false)}
273	              ref={arrowRef}
274	            />
275	          </Tooltip>
276	          <Tooltip
277	            content={pageButtonTips()}
278	            trigger={tooltipsTrigger}
279	            isVisible={tooltipsTrigger === 'manual' ? false : undefined}
280	          >
281	            <Button
282	              icon={<AngleLeftIcon />}
283	              variant="plain"
284	              className={`metrics-content-button ${loading ? 'loading' : ''}`}
285	              onClick={() => moveHistogramRange(false)}
286	              ref={pageRef}
287	            />
288	          </Tooltip>
289	        </FlexItem>
290	        <FlexItem>
291	          <Text component={TextVariants.p}>{getDomainDisplayText(displayedRange || range || defaultRange)}</Text>
292	        </FlexItem>
293	        <FlexItem>
294	          <Tooltip
295	            content={pageButtonTips()}
296	            trigger={tooltipsTrigger}
297	            isVisible={tooltipsTrigger === 'manual' ? false : undefined}
298	          >
299	            <Button
300	              icon={<AngleRightIcon />}
301	              variant="plain"
302	              className={`metrics-content-button ${loading ? 'loading' : ''}`}
303	              onClick={() => moveHistogramRange(true)}
304	            />
305	          </Tooltip>
306	          <Tooltip
307	            content={arrowButtonTips()}
308	            trigger={tooltipsTrigger}
309	            isVisible={tooltipsTrigger === 'manual' ? false : undefined}
310	          >
311	            <Button
312	              icon={<AngleDoubleRightIcon />}
313	              variant="plain"
314	              className={`metrics-content-button ${loading ? 'loading' : ''}`}
315	              onClick={() => moveRange(true)}
316	            />
317	          </Tooltip>
318	        </FlexItem>
319	        <FlexItem flex={{ default: 'flex_1' }}>
320	          <Flex className="histogram-zoom-container" direction={{ default: 'row' }}>
321	            <FlexItem>
322	              <Tooltip
323	                content={zoomButtonTips()}
324	                trigger={tooltipsTrigger}
325	                isVisible={tooltipsTrigger === 'manual' ? false : undefined}
326	              >
327	                <Button
328	                  icon={<SearchMinusIcon />}
329	                  variant="plain"
330	                  className={`metrics-content-button ${loading ? 'loading' : ''}`}
331	                  onClick={() => zoomRange(false)}
332	                  ref={zoomRef}
333	                />
334	              </Tooltip>
335	            </FlexItem>
336	            <FlexItem>
337	              <Tooltip
338	                content={zoomButtonTips()}
339	                trigger={tooltipsTrigger}
340	                isVisible={tooltipsTrigger === 'manual' ? false : undefined}
341	              >
342	                <Button
343	                  icon={<SearchPlusIcon />}
344	                  variant="plain"
345	                  className={`metrics-content-button ${loading ? 'loading' : ''}`}
346	                  onClick={() => zoomRange(true)}
347	                />
348	              </Tooltip>
349	            </FlexItem>
350	          </Flex>
351	        </FlexItem>
352	        <FlexItem>
353	          <Button
354	            icon={<QuestionCircleIcon />}
355	            variant="plain"
356	            className={`metrics-content-button ${loading ? 'loading' : ''}`}
357	            onClick={() => guidedTourHandle?.startTour()}
358	          />
359	        </FlexItem>
360	      </Flex>
361	      <Chart
362	        themeColor={ChartThemeColor.multiUnordered}
363	        containerComponent={
364	          <VoronoiContainer
365	            brushDimension="x"
366	            onBrushDomainChange={(updated?: { x?: Array<Date | number> }) => {
367	              if (limit && updated?.x && updated.x.length && typeof updated.x[0] === 'object') {
368	                const start = getDateMsInSeconds(updated.x[0].getTime());
369	                const range = getHistogramRangeFromLimit(totalMetric, limit, start);
370	
371	                if (range.from < range.to) {
372	                  updated.x = getDomainFromRange(range);
373	                  setDisplayedRange(range);
374	                }
375	              }
376	            }}
377	            onBrushDomainChangeEnd={(domain?: { x?: Array<Date | number> }) => {
378	              containerRef.current?.focus();
379	              if (
380	                domain?.x &&
381	                domain.x.length > 1 &&
382	                typeof domain.x[0] === 'object' &&
383	                typeof domain.x[1] === 'object'
384	              ) {
385	                const start = domain.x[0];
386	                const end = domain.x[1];
387	
388	                if (start.getTime() < end.getTime()) {
389	                  setRange({ from: getDateMsInSeconds(start.getTime()), to: getDateMsInSeconds(end.getTime()) });
390	                }
391	              }
392	            }}
393	            handleComponent={<BrushHandleComponent isDark={isDark} />}
394	            defaultBrushArea="none"
395	            handleWidth={1}
396	            brushStyle={{ stroke: 'transparent', fill: 'black', fillOpacity: 0.1 }}
397	            brushDomain={{
398	              x: getDomainFromRange(range ? range : defaultRange)
399	            }}
400	          />
401	        }
402	        //TODO: fix refresh on selection change to enable animation
403	        //animate={true}
404	        scale={{ x: 'time', y: 'linear' }}
405	        width={dimensions.width}
406	        height={dimensions.height}
407	        padding={{
408	          top: 45,
409	          right: 25,
410	          bottom: 40,
411	          left: 60
412	        }}
413	      >
414	        <ChartAxis animate={animate} fixLabelOverlap />
415	        <ChartAxis
416	          animate={animate}
417	          dependentAxis
418	          showGrid
419	          fixLabelOverlap
420	          tickFormat={y => getFormattedValue(y, 'Flows', 'sum', t)}
421	        />
422	        <ChartStack>
423	          <ChartBar
424	            animate={animate}
425	            name={`bar-${id}`}
426	            key={`bar-${id}`}
427	            data={datapoints}
428	            barWidth={(dimensions.width / datapoints.length) * 0.8}
429	            alignment={'start'}
430	          />
431	        </ChartStack>
432	      </Chart>
433	    </div>
434	  );
435	};
436	
437	export const HistogramContainer: React.FC<{
438	  id: string;
439	  loading: boolean;
440	  totalMetric: TopologyMetrics | undefined;
441	  limit: number;
442	  isDark: boolean;
443	  range?: TimeRange;
444	  guidedTourHandle: GuidedTourHandle | null;
445	  setRange: (tr: TimeRange) => void;
446	  moveRange: (next: boolean) => void;
447	  zoomRange: (zoom: boolean) => void;
448	  resetRange: () => void;
449	}> = ({
450	  id,
451	  loading,
452	  totalMetric,
453	  limit,
454	  isDark,
455	  range,
456	  guidedTourHandle,
457	  setRange,
458	  moveRange,
459	  zoomRange,
460	  resetRange
461	}) => {
462	  const { t } = useTranslation('plugin__netobserv-plugin');
463	
464	  return totalMetric ? (
465	    <Histogram
466	      id={id}
467	      loading={loading}
468	      totalMetric={toNamedMetric(t, totalMetric, TruncateLength.OFF, false, false)}
469	      limit={limit}
470	      isDark={isDark}
471	      range={range}
472	      guidedTourHandle={guidedTourHandle}
473	      setRange={setRange}
474	      moveRange={moveRange}
475	      zoomRange={zoomRange}
476	    />
477	  ) : loading ? (
478	    <Bullseye data-test="loading-histogram">
479	      <Spinner size="xl" />
480	    </Bullseye>
481	  ) : (
482	    <Bullseye data-test="no-datapoints-found">
483	      <EmptyState variant={EmptyStateVariant.full} isFullHeight>
484	        <EmptyStateHeader titleText={t('No datapoints found in the selected time range')} headingLevel="h6" />
485	        <EmptyStateBody>{t('Reset time range and try again.')}</EmptyStateBody>
486	        <Button id="reset-timerange-button" data-test="reset-timerange-button" variant="link" onClick={resetRange}>
487	          {t('Reset time range')}
488	        </Button>
489	      </EmptyState>
490	    </Bullseye>
491	  );
492	};
493	
494	export default HistogramContainer;

