 64	export const Histogram: React.FC<HistogramProps> = ({
 65	  id,
 66	  loading,
 67	  totalMetric,
 68	  limit,
 69	  isDark,
 70	  range,
 71	  guidedTourHandle,
 72	  setRange,
 73	  moveRange,
 74	  zoomRange
 75	}) => {
 76	  const { t } = useTranslation('plugin__netobserv-plugin');
 77	
 78	  const datapoints: ChartDataPoint[] = toHistogramDatapoints(totalMetric);
