 80	  const [displayedRange, setDisplayedRange] = React.useState<TimeRange>();
 81	
 82	  React.useEffect(() => {
 83	    if (range) {
 84	      setDisplayedRange(range);
 85	    }
 86	  }, [range]);
 87	
 88	  const [tooltipsTrigger, setTooltipsTrigger] = React.useState<'manual' | 'mouseenter'>('mouseenter');
 89	  const containerRef = React.useRef<HTMLDivElement>(null);
 90	  const zoomRef = React.createRef<HTMLInputElement>();
 91	  const pageRef = React.createRef<HTMLInputElement>();
 92	  const arrowRef = React.createRef<HTMLInputElement>();
 93	
 94	  // eslint-disable-next-line @typescript-eslint/no-explicit-any
 95	  const animate: any = {
 96	    duration: 1500,
 97	    animationWhitelist: ['data', 'domain']
 98	  };
 99	
100	  const [dimensions, setDimensions] = React.useState<Dimensions>({ width: 3000, height: 250 });
101	  React.useEffect(() => {
102	    return observeDimensions(containerRef, dimensions, setDimensions);
103	  }, [containerRef, dimensions, setDimensions]);
104	
105	  const moveHistogramRange = React.useCallback(
106	    (next: boolean) => {
107	      containerRef.current?.focus();
108	
109	      const r = range ? range : defaultRange;
110	      const rSize = r.to - r.from;
111	
112	      let start = r.from - rSize;
113	      if (next) {
114	        start = r.to;
115	      }
116	      const end = start + rSize;
117	
118	      //try to get new range using limit
119	      let updatedRange = getHistogramRangeFromLimit(totalMetric, limit, start);
120	
121	      //else fallback on previous / next range keeping actual width
122	      if (!updatedRange.from || !updatedRange.to) {
123	        const minTime = getDateMsInSeconds(Math.min(...datapoints.map(dp => dp.x.getTime())));
124	        const maxTime = getDateMsInSeconds(Math.max(...datapoints.map(dp => dp.x.getTime())));
