131	
132	      if (updatedRange.from && updatedRange.to && updatedRange.from < updatedRange.to) {
133	        setRange(updatedRange);
134	      } else {
135	        setRange(defaultRange);
136	      }
137	    },
138	    [containerRef, datapoints, defaultRange, limit, range, setRange, totalMetric]
