147	        case 'ArrowLeft':
148	          moveRange(false);
149	          break;
150	        case '+':
151	          zoomRange(true);
152	          break;
153	        case '-':
154	          zoomRange(false);
155	          break;
156	        case 'PageUp':
157	          moveHistogramRange(true);
158	          break;
159	        case 'PageDown':
160	          moveHistogramRange(false);
161	          break;
162	      }
163	    },
164	    [moveHistogramRange, moveRange, zoomRange]
165	  );
166	
167	  const zoomButtonTips = React.useCallback(() => {
168	    return t(
169	      // eslint-disable-next-line max-len
170	      'Zoom in / zoom out the histogram displayed time range. The selected time range in the top right corner will adapt accordingly. You can also use the plus or minus buttons while the histogram is focused.'
171	    );
172	  }, [t]);
173	
174	  const pageButtonTips = React.useCallback(() => {
175	    return t(
176	      // eslint-disable-next-line max-len
177	      'Move the selected range to filter the table below as time based pagination. You can also use the page up or down buttons while the histogram is focused.'
178	    );
179	  }, [t]);
180	
181	  const arrowButtonTips = React.useCallback(() => {
182	    return t(
183	      // eslint-disable-next-line max-len
184	      'Shift the histogram displayed time range. The selected time range in the top right corner will adapt accordingly. You can also use the arrow left or right buttons while the histogram is focused.'
185	    );
186	  }, [t]);
187	
188	  const [guidedTourDone, setGuidedTourDone] = useLocalStorage<boolean>(localStorageHistogramGuidedTourDoneKey);
189	  React.useEffect(() => {
190	    if (!guidedTourHandle) {
191	      return;
192	    }
193	
194	    guidedTourHandle.clearOnIndexChangeListener();
195	    guidedTourHandle.updateTourItems([
196	      {
197	        title: t('Histogram'),
198	        description: t(
199	          // eslint-disable-next-line max-len
200	          'The following bar chart represents the number of logs over time. You can select a portion of it to drill down into the selected time range, accordingly/consequently filtering the following flows information.'
201	        ),
202	        assetName: 'histogram.gif',
203	        minWidth: '600px',
204	        ref: containerRef
205	      },
206	      {
207	        title: t('Zoom buttons'),
208	        description: zoomButtonTips(),
209	        assetName: 'histogram-zoom.gif',
210	        position: PopoverPosition.bottom,
211	        ref: zoomRef
212	      },
213	      {
214	        title: t('Arrow buttons'),
215	        description: arrowButtonTips(),
216	        ref: arrowRef
217	      },
218	      {
219	        title: t('Page buttons'),
220	        description: pageButtonTips(),
221	        assetName: 'histogram-pages.gif',
222	        minWidth: '600px',
223	        position: PopoverPosition.bottom,
224	        ref: pageRef
225	      }
226	    ]);
227	
228	    if (!guidedTourDone) {
229	      setGuidedTourDone(true);
230	      guidedTourHandle.startTour();
231	    }
232	
233	    guidedTourHandle.addOnIndexChangeListener(index =>
234	      setTooltipsTrigger(index !== undefined ? 'manual' : 'mouseenter')
235	    );
236	  }, [
237	    arrowButtonTips,
238	    arrowRef,
239	    containerRef,
240	    guidedTourDone,
241	    guidedTourHandle,
242	    pageButtonTips,
243	    pageRef,
244	    setGuidedTourDone,
245	    t,
246	    zoomButtonTips,
247	    zoomRef
