287	            />
288	          </Tooltip>
289	        </FlexItem>
290	        <FlexItem>
291	          <Text component={TextVariants.p}>{getDomainDisplayText(displayedRange || range || defaultRange)}</Text>
292	        </FlexItem>
293	        <FlexItem>
294	          <Tooltip
295	            content={pageButtonTips()}
296	            trigger={tooltipsTrigger}
297	            isVisible={tooltipsTrigger === 'manual' ? false : undefined}
298	          >
299	            <Button
300	              icon={<AngleRightIcon />}
301	              variant="plain"
302	              className={`metrics-content-button ${loading ? 'loading' : ''}`}
303	              onClick={() => moveHistogramRange(true)}
304	            />
305	          </Tooltip>
306	          <Tooltip
307	            content={arrowButtonTips()}
308	            trigger={tooltipsTrigger}
309	            isVisible={tooltipsTrigger === 'manual' ? false : undefined}
310	          >
311	            <Button
312	              icon={<AngleDoubleRightIcon />}
313	              variant="plain"
