390	                }
391	              }
392	            }}
393	            handleComponent={<BrushHandleComponent isDark={isDark} />}
394	            defaultBrushArea="none"
395	            handleWidth={1}
396	            brushStyle={{ stroke: 'transparent', fill: 'black', fillOpacity: 0.1 }}
397	            brushDomain={{
398	              x: getDomainFromRange(range ? range : defaultRange)
399	            }}
400	          />
401	        }
402	        //TODO: fix refresh on selection change to enable animation
403	        //animate={true}
404	        scale={{ x: 'time', y: 'linear' }}
405	        width={dimensions.width}
406	        height={dimensions.height}
407	        padding={{
408	          top: 45,
409	          right: 25,
410	          bottom: 40,
411	          left: 60
412	        }}
413	      >
