438	export const HistogramContainer: React.FC<{
439	  id: string;
440	  loading: boolean;
441	  totalMetric: TopologyMetrics | undefined;
442	  limit: number;
443	  isDark: boolean;
444	  range?: TimeRange;
445	  guidedTourHandle: GuidedTourHandle | null;
446	  setRange: (tr: TimeRange) => void;
447	  moveRange: (next: boolean) => void;
448	  zoomRange: (zoom: boolean) => void;
449	  resetRange: () => void;
450	}> = ({
451	  id,
452	  loading,
453	  totalMetric,
454	  limit,
455	  isDark,
456	  range,
457	  guidedTourHandle,
458	  setRange,
459	  moveRange,
460	  zoomRange,
461	  resetRange
462	}) => {
463	  const { t } = useTranslation('plugin__netobserv-plugin');
464	
465	  return totalMetric ? (
466	    <Histogram
467	      id={id}
468	      loading={loading}
469	      totalMetric={toNamedMetric(t, totalMetric, TruncateLength.OFF, false, false)}
470	      limit={limit}
471	      isDark={isDark}
472	      range={range}
473	      guidedTourHandle={guidedTourHandle}
474	      setRange={setRange}
475	      moveRange={moveRange}
476	      zoomRange={zoomRange}
477	    />
478	  ) : loading ? (
479	    <Bullseye data-test="loading-histogram">
480	      <Spinner size="xl" />
481	    </Bullseye>
482	  ) : (
483	    <Bullseye data-test="no-datapoints-found">
484	      <EmptyState variant={EmptyStateVariant.full} isFullHeight titleText={t('No datapoints found in the selected time range')} headingLevel="h6">
485	        <EmptyStateBody>{t('Reset time range and try again.')}</EmptyStateBody>
486	        <EmptyStateFooter>
487	          <Button id="reset-timerange-button" data-test="reset-timerange-button" variant="link" onClick={resetRange}>
488	            {t('Reset time range')}
489	          </Button>
490	        </EmptyStateFooter>
491	      </EmptyState>
492	    </Bullseye>
493	  );
494	};
495	
496	export default HistogramContainer;

