235	      setTooltipsTrigger(index !== undefined ? 'manual' : 'mouseenter')
236	    );
237	  }, [
238	    arrowButtonTips,
239	    arrowRef,
240	    containerRef,
241	    guidedTourDone,
242	    guidedTourHandle,
243	    pageButtonTips,
244	    pageRef,
245	    setGuidedTourDone,
246	    t,
247	    zoomButtonTips,
248	    zoomRef
249	  ]);
250	
251	  return (
252	    <div
253	      id={`chart-${id}`}
254	      className={`metrics-content-div ${loading ? 'loading' : ''}`}
255	      ref={containerRef}
256	      tabIndex={0}
257	      onKeyDown={e => onKeyDown(e.key)}
258	    >
259	      <Flex className="histogram-range-container" direction={{ default: 'row' }}>
260	        <FlexItem flex={{ default: 'flex_1' }}>
261	          <Content component={ContentVariants.p}>{t('Number of logs over time')}</Content>
262	        </FlexItem>
263	        <FlexItem>
264	          <Tooltip
265	            content={arrowButtonTips()}
266	            trigger={tooltipsTrigger}
267	            isVisible={tooltipsTrigger === 'manual' ? false : undefined}
268	          >
269	            <Button
270	              icon={<AngleDoubleLeftIcon />}
271	              variant="plain"
272	              className={`metrics-content-button ${loading ? 'loading' : ''}`}
273	              onClick={() => moveRange(false)}
274	              ref={arrowRef}
275	            />
276	          </Tooltip>
277	          <Tooltip
278	            content={pageButtonTips()}
279	            trigger={tooltipsTrigger}
280	            isVisible={tooltipsTrigger === 'manual' ? false : undefined}
281	          >
282	            <Button
283	              icon={<AngleLeftIcon />}
284	              variant="plain"
285	              className={`metrics-content-button ${loading ? 'loading' : ''}`}
286	              onClick={() => moveHistogramRange(false)}
287	              ref={pageRef}
288	            />
289	          </Tooltip>
290	        </FlexItem>
291	        <FlexItem>
292	          <Content component={ContentVariants.p}>{getDomainDisplayText(displayedRange || range || defaultRange)}</Content>
293	        </FlexItem>
294	        <FlexItem>
295	          <Tooltip
296	            content={pageButtonTips()}
297	            trigger={tooltipsTrigger}
298	            isVisible={tooltipsTrigger === 'manual' ? false : undefined}
299	          >
300	            <Button
301	              icon={<AngleRightIcon />}
302	              variant="plain"
303	              className={`metrics-content-button ${loading ? 'loading' : ''}`}
304	              onClick={() => moveHistogramRange(true)}
305	            />
306	          </Tooltip>
307	          <Tooltip
308	            content={arrowButtonTips()}
309	            trigger={tooltipsTrigger}
310	            isVisible={tooltipsTrigger === 'manual' ? false : undefined}
311	          >
312	            <Button
313	              icon={<AngleDoubleRightIcon />}
314	              variant="plain"
315	              className={`metrics-content-button ${loading ? 'loading' : ''}`}
316	              onClick={() => moveRange(true)}
317	            />
318	          </Tooltip>
319	        </FlexItem>
320	        <FlexItem flex={{ default: 'flex_1' }}>
321	          <Flex className="histogram-zoom-container" direction={{ default: 'row' }}>
322	            <FlexItem>
323	              <Tooltip
324	                content={zoomButtonTips()}
325	                trigger={tooltipsTrigger}
326	                isVisible={tooltipsTrigger === 'manual' ? false : undefined}
327	              >
328	                <Button
329	                  icon={<SearchMinusIcon />}
330	                  variant="plain"
331	                  className={`metrics-content-button ${loading ? 'loading' : ''}`}
332	                  onClick={() => zoomRange(false)}
333	                  ref={zoomRef}
334	                />
335	              </Tooltip>
336	            </FlexItem>
337	            <FlexItem>
338	              <Tooltip
339	                content={zoomButtonTips()}
340	                trigger={tooltipsTrigger}
341	                isVisible={tooltipsTrigger === 'manual' ? false : undefined}
342	              >
343	                <Button
344	                  icon={<SearchPlusIcon />}
345	                  variant="plain"
346	                  className={`metrics-content-button ${loading ? 'loading' : ''}`}
347	                  onClick={() => zoomRange(true)}
348	                />
349	              </Tooltip>
350	            </FlexItem>
351	          </Flex>
352	        </FlexItem>
353	        <FlexItem>
354	          <Button
355	            icon={<QuestionCircleIcon />}
356	            variant="plain"
357	            className={`metrics-content-button ${loading ? 'loading' : ''}`}
358	            onClick={() => guidedTourHandle?.startTour()}
359	          />
360	        </FlexItem>
361	      </Flex>
362	      <Chart
363	        themeColor={ChartThemeColor.multiUnordered}
364	        containerComponent={
365	          <VoronoiContainer
366	            brushDimension="x"
367	            onBrushDomainChange={(updated?: { x?: Array<Date | number> }) => {
368	              if (limit && updated?.x && updated.x.length && typeof updated.x[0] === 'object') {
369	                const start = getDateMsInSeconds(updated.x[0].getTime());
370	                const range = getHistogramRangeFromLimit(totalMetric, limit, start);
371	
372	                if (range.from < range.to) {
373	                  updated.x = getDomainFromRange(range);
374	                  setDisplayedRange(range);
375	                }
376	              }
377	            }}
378	            onBrushDomainChangeEnd={(domain?: { x?: Array<Date | number> }) => {
379	              containerRef.current?.focus();
380	              if (
381	                domain?.x &&
382	                domain.x.length > 1 &&
383	                typeof domain.x[0] === 'object' &&
384	                typeof domain.x[1] === 'object'
385	              ) {
386	                const start = domain.x[0];
387	                const end = domain.x[1];
388	
389	                if (start.getTime() < end.getTime()) {
390	                  setRange({ from: getDateMsInSeconds(start.getTime()), to: getDateMsInSeconds(end.getTime()) });
391	                }
392	              }
393	            }}
394	            handleComponent={<BrushHandleComponent isDark={isDark} />}
395	            defaultBrushArea="none"
396	            handleWidth={1}
397	            brushStyle={{ stroke: 'transparent', fill: 'black', fillOpacity: 0.1 }}
398	            brushDomain={{
399	              x: getDomainFromRange(range ? range : defaultRange)
400	            }}
401	          />
402	        }
403	        //TODO: fix refresh on selection change to enable animation
404	        //animate={true}
405	        scale={{ x: 'time', y: 'linear' }}
406	        width={dimensions.width}
407	        height={dimensions.height}
408	        padding={{
409	          top: 45,
410	          right: 25,
411	          bottom: 40,
412	          left: 60
413	        }}
414	      >
415	        <ChartAxis animate={animate} fixLabelOverlap />
416	        <ChartAxis
417	          animate={animate}
418	          dependentAxis
419	          showGrid
420	          fixLabelOverlap
421	          tickFormat={y => getFormattedValue(y, 'Flows', 'sum', t)}
422	        />
423	        <ChartStack>
424	          <ChartBar
425	            animate={animate}
426	            name={`bar-${id}`}
427	            key={`bar-${id}`}
428	            data={datapoints}
429	            barWidth={(dimensions.width / datapoints.length) * 0.8}
430	            alignment={'start'}
431	          />
432	        </ChartStack>
433	      </Chart>
434	    </div>
435	  );
436	};
