439	  id: string;
440	  loading: boolean;
441	  totalMetric: TopologyMetrics | undefined;
442	  limit: number;
443	  isDark: boolean;
444	  range?: TimeRange;
445	  guidedTourHandle: GuidedTourHandle | null;
